import { createClient } from "@supabase/supabase-js"

const supabase = createClient(
  process.env.VITE_SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_KEY! // usar service key para bypass RLS
)

async function upsert(table: string, data: any[], conflictCol = "id") {
  const { error } = await supabase.from(table).upsert(data, {
    onConflict: conflictCol,
    ignoreDuplicates: false,
  })
  if (error) console.error(`Erro em ${table}:`, error.message)
  else console.log(`✅ ${table}: ${data.length} registos`)
}

